// --- Security: SQL Validator ---

sealed trait ValidationResult
case object Valid extends ValidationResult
case class Invalid(reason: String) extends ValidationResult

class SqlQueryValidator(allowedDatabases: Set[String], allowedTables: Set[String]) {

  // Disallowed SQL keywords/patterns (case-insensitive)
  private val disallowedPatterns: List[(String, String)] = List(
    ("""(?i)\b(DROP|ALTER|CREATE|TRUNCATE|DELETE|UPDATE|INSERT|MERGE|REPLACE)\b""", "DDL/DML statements are not allowed"),
    ("""(?i)\b(GRANT|REVOKE|DENY)\b""", "Permission statements are not allowed"),
    ("""(?i)\bINTO\s+OUTFILE\b""", "File output is not allowed"),
    ("""(?i)\bLOAD\s+DATA\b""", "Data loading is not allowed"),
    ("""(?i)\bSET\b""", "SET statements are not allowed"),
    ("""(?i)\bUSE\b""", "USE statements are not allowed"),
    ("""(?i)\bCALL\b""", "Stored procedure calls are not allowed"),
    ("""(?i)\bEXEC(UTE)?\b""", "EXEC statements are not allowed"),
    ("""(?i)\bSHOW\s+(DATABASES|SCHEMAS|TABLES|COLUMNS|CREATE)\b""", "SHOW statements are not allowed"),
    ("""(?i)\bDESCRIBE\b""", "DESCRIBE statements are not allowed"),
    ("""(?i)\bEXPLAIN\b""", "EXPLAIN statements are not allowed"),
    ("""(?i)\bADD\s+(JAR|FILE|ARCHIVE)\b""", "Adding external resources is not allowed"),
    ("""(?i)\bCACHE\b""", "CACHE statements are not allowed"),
    ("""(?i)\bUNDO\b""", "UNDO statements are not allowed"),
    ("""(?i)/\*.*\*/""", "Block comments are not allowed"),
    ("""--""", "Line comments are not allowed"),
    ("""(?i)\bcsv\s*\.""", "Direct file access is not allowed"),
    ("""(?i)\bparquet\s*\.""", "Direct file access is not allowed"),
    ("""(?i)\bjson\s*\.""", "Direct file access is not allowed"),
    ("""(?i)\borc\s*\.""", "Direct file access is not allowed"),
    ("""(?i)\btext\s*\.""", "Direct file access is not allowed"),
    ("""(?i)\bjdbc\s*\.""", "Direct JDBC access is not allowed"),
    ("""(?i)file:/""", "File system access is not allowed"),
    ("""(?i)hdfs:/""", "Direct HDFS access is not allowed"),
    ("""(?i)s3[an]?:/""", "Direct S3 access is not allowed"),
    ("""(?i)gs:/""", "Direct GCS access is not allowed"),
    ("""(?i)abfss?:/""", "Direct Azure storage access is not allowed"),
    (""";""", "Multiple statements (semicolons) are not allowed"),
    ("""(?i)\bUNION\s+ALL\s+SELECT\b.*\bFROM\b""", "Complex UNION queries require review")
  )

  def validate(sql: String): ValidationResult = {
    val trimmedSql = sql.trim

    if (trimmedSql.isEmpty) {
      return Invalid("Query cannot be empty")
    }

    if (trimmedSql.length > 10000) {
      return Invalid("Query exceeds maximum length of 10,000 characters")
    }

    // Check disallowed patterns
    for ((pattern, reason) <- disallowedPatterns) {
      if (pattern.r.findFirstIn(trimmedSql).isDefined) {
        return Invalid(reason)
      }
    }

    // Must start with SELECT or WITH (CTEs)
    if (!trimmedSql.matches("""(?is)\s*(SELECT|WITH)\b.*""")) {
      return Invalid("Only SELECT queries (including CTEs with WITH) are allowed")
    }

    // Parse and validate table references using Spark's Catalyst parser
    validateTableReferences(trimmedSql) match {
      case Some(error) => Invalid(error)
      case None => Valid
    }
  }

  private def validateTableReferences(sql: String): Option[String] = {
    Try {
      val logicalPlan = CatalystSqlParser.parsePlan(sql)
      val tableRefs = extractTableReferences(logicalPlan)

      tableRefs.foreach { tableRef =>
        val parts = tableRef.split("\\.")
        parts.length match {
          case 1 =>
            val tableName = parts(0).toLowerCase
            if (!allowedTables.contains(tableName)) {
              return Some(s"Access denied: table '$tableName' is not in the allowed list")
            }
          case 2 =>
            val dbName = parts(0).toLowerCase
            val tableName = parts(1).toLowerCase
            if (!allowedDatabases.contains(dbName)) {
              return Some(s"Access denied: database '$dbName' is not in the allowed list")
            }
            val fullName = s"$dbName.$tableName"
            if (!allowedTables.contains(tableName) && !allowedTables.contains(fullName)) {
              return Some(s"Access denied: table '$fullName' is not in the allowed list")
            }
          case _ =>
            return Some(s"Invalid table reference: '$tableRef'")
        }
      }
      None
    } match {
      case Success(result) => result
      case Failure(e) => Some(s"Failed to parse SQL query: ${e.getMessage}")
    }
  }

  private def extractTableReferences(plan: LogicalPlan): Set[String] = {
    val tables = mutable.Set[String]()

    def traverse(node: LogicalPlan): Unit = {
      node match {
        case UnresolvedRelation(multipartIdentifier, _, _) =>
          tables += multipartIdentifier.mkString(".")
        case _ =>
      }
      node.children.foreach(traverse)

      // Handle subqueries in expressions
      node.expressions.foreach { expr =>
        expr.collect {
          case subquery: org.apache.spark.sql.catalyst.expressions.SubqueryExpression =>
            traverse(subquery.plan)
        }
      }
    }

    traverse(plan)
    tables.toSet
  }
}

// --- Rate Limiter ---

class RateLimiter(maxRequestsPerMinute: Int) {
  private val requestTimestamps = mutable.Map[String, mutable.Queue[Long]]()

  def isAllowed(userId: String): Boolean = synchronized {
    val now = System.currentTimeMillis()
    val oneMinuteAgo = now - 60000

    val timestamps = requestTimestamps.getOrElseUpdate(userId, mutable.Queue.empty)

    // Remove old timestamps
    while (timestamps.nonEmpty && timestamps.front < oneMinuteAgo) {
      timestamps.dequeue()
    }

    if (timestamps.size < maxRequestsPerMinute) {
      timestamps.enqueue(now)
      true
    } else {
      false
    }
  }
}

// --- Query Executor with Resource Controls ---

class SecureQueryExecutor(spark: SparkSession, validator: SqlQueryValidator) {

  private val defaultMaxRows: Int = 10000
  private val absoluteMaxRows: Int = 100000
  private val defaultTimeoutSeconds: Int = 120
  private val maxTimeoutSeconds: Int = 600

  private val scheduledExecutor = Executors.newScheduledThreadPool(2)
  private val queryExecutor = ExecutionContext.fromExecutorService(
    Executors.newFixedThreadPool(10)
  )

  def executeQuery(request: QueryRequest): Future[QueryResponse] = {
    val queryId = java.util.UUID.randomUUID().toString
    val maxRows = math.min(request.maxRows.getOrElse(defaultMaxRows), absoluteMaxRows)
    val timeout = math.min(request.timeoutSeconds.getOrElse(defaultTimeoutSeconds), maxTimeoutSeconds)

    // Step 1: Validate
    validator.validate(request.sql) match {
      case Invalid(reason) =>
        Future.successful(QueryResponse(
          status = "error",
          data = None,
          schema = None,
          rowCount = None,
          error = Some(s"Query validation failed: $reason"),
          queryId = queryId
        ))
      case Valid =>
        executeWithTimeout(request.sql, queryId, maxRows, timeout)
    }
  }

  private def executeWithTimeout(
    sql: String,
    queryId: String,
    maxRows: Int,
    timeoutSeconds: Int
  ): Future[QueryResponse] = {
    val promise = Promise[QueryResponse]()

    val executionFuture = Future {
      try {
        // Set Spark job group for cancellation support
        spark.sparkContext.setJobGroup(queryId, s"User query: $queryId", interruptOnCancel = true)

        // Set resource constraints via Spark configs for this thread
        spark.sparkContext.setLocalProperty("spark.scheduler.pool", "user_queries")

        val df: DataFrame = spark.sql(sql)

        // Enforce row limit with LIMIT pushed into the plan
        val limitedDf = df.limit(maxRows)
        val rows = limitedDf.collect()

        val schema = limitedDf.schema.fields.map(f =>
          ColumnInfo(f.name, f.dataType.simpleString)
        ).toList

        val data = rows.map { row =>
          schema.zipWithIndex.map { case (col, idx) =>
            val value: JsValue = if (row.isNullAt(idx)) JsNull
            else {
              row.get(idx) match {
                case s: String => JsString(s)
                case n: java.lang.Number => JsNumber(BigDecimal(n.toString))
                case b: Boolean => JsBoolean(b)
                case ts: java.sql.Timestamp => JsString(ts.toString)
                case d: java.sql.Date => JsString(d.toString)
                case other => JsString(Option(other).map(_.toString).getOrElse("null"))
              }
            }
            col.name -> value
          }.toMap
        }.toList

        QueryResponse(
          status = "success",
          data = Some(data),
          schema = Some(schema),
          rowCount = Some(data.size),
          error = None,
          queryId = queryId
        )
      } catch {
        case _: InterruptedException =>
          QueryResponse(
            status = "error", data = None, schema = None, rowCount = None,
            error = Some("Query was cancelled due to timeout"),
            queryId = queryId
          )
        case e: Exception =>
          QueryResponse(
            status = "error", data = None, schema = None, rowCount = None,
            error = Some(s"Query execution failed: ${sanitizeErrorMessage(e.getMessage)}"),
            queryId = queryId
          )
      } finally {
        spark.sparkContext.clearJobGroup()
      }
    }(queryExecutor)

    // Set up timeout
    val timeoutTask = scheduledExecutor.schedule(new Runnable {
      override def run(): Unit = {
        if (!promise.isCompleted) {
          spark.sparkContext.cancelJobGroup(queryId)
          promise.trySuccess(QueryResponse(
            status = "error", data = None, schema = None, rowCount = None,
            error = Some(s"Query timed out after $timeoutSeconds seconds"),
            queryId = queryId
          ))
        }
      }
    }, timeoutSeconds, TimeUnit.SECONDS)

    executionFuture.onComplete { result =>
      timeoutTask.cancel(false)
      result match {
        case Success(response) => promise.trySuccess(response)
        case Failure(e) => promise.trySuccess(QueryResponse(
          status = "error", data = None, schema = None, rowCount = None,
          error = Some(s"Unexpected error: ${sanitizeErrorMessage(e.getMessage)}"),
          queryId = queryId
        ))
      }
    }(queryExecutor)

    promise.future
  }

  private def sanitizeErrorMessage(msg: String): String = {
    if (msg == null) "Unknown error"
    else {
      // Remove file paths, internal class names, etc.
      msg
        .replaceAll("""(?i)(file|hdfs|s3[an]?|gs|abfss?)://[^\s]+""", "[path redacted]")
        .replaceAll("""at\s+[\w.$]+\([\w.]+:\d+\)""", "")
        .take(500)
    }
  }

  def shutdown(): Unit = {
    scheduledExecutor.shutdown()
    queryExecutor.asInstanceOf[java.util.concurrent.ExecutorService].shutdown()
  }
}

// --- Audit Logger ---

class AuditLogger(spark: SparkSession) {
  import spark.implicits._

  case class AuditEntry(
    timestamp: Long,
    userId: String,
    queryId: String,
    sql: String,
    status: String,
    errorMessage: Option[String],
    executionTimeMs: Long
  )

  private val auditBuffer = mutable.ListBuffer[AuditEntry]()
  private val bufferSize = 100

  def log(userId: String, queryId: String, sql: String, status: String,
          errorMessage: Option[String], executionTimeMs: Long): Unit = synchronized {
    val entry = AuditEntry(
      System.currentTimeMillis(), userId, queryId,
      sql.take(2000), // Truncate for storage
      status, errorMessage.map(_.take(500)), executionTimeMs
    )
    auditBuffer += entry

    // Flush if buffer is full
    if (auditBuffer.size >= bufferSize) {
      flush()
    }
  }

  def flush(): Unit = synchronized {
    if (auditBuffer.nonEmpty) {
      try {
        val entries = auditBuffer.toList
        auditBuffer.clear()
        val df = entries.toDF()
        df.write.mode("append").parquet("/data/audit/query_logs")
      } catch {
        case e: Exception =>
          System.err.println(s"Failed to flush audit log: ${e.getMessage}")
      }
    }
  }
}

