// --- Main Application ---

object SecureAnalyticsPlatform {

  def main(args: Array[String]): Unit = {

    val spark = SparkSession.builder()
      .appName("Secure Analytics Platform")
      .config("spark.scheduler.mode", "FAIR")
      .config("spark.sql.adaptive.enabled", "true")
      .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
      // Limit broadcast join size to prevent memory issues
      .config("spark.sql.autoBroadcastJoinThreshold", "10485760") // 10MB
      // Prevent access to Hive SerDes that could execute arbitrary code
      .config("spark.sql.hive.convertMetastoreParquet", "true")
      .config("spark.sql.hive.convertMetastoreOrc", "true")
      .enableHiveSupport()
      .getOrCreate()

    // Register sample data for demonstration
    registerSampleData(spark)

    val permissionsStore = new PermissionsStore()
    val rateLimiter = new RateLimiter(maxRequestsPerMinute = 60)
    val auditLogger = new AuditLogger(spark)

    implicit val system: ActorSystem = ActorSystem("analytics-platform")
    implicit val ec: ExecutionContext = system.dispatcher

    import JsonProtocol._

    val route: Route =
      pathPrefix("api" / "v1") {
        path("query") {
          post {
            entity(as[QueryRequest]) { request =>
              val startTime = System.currentTimeMillis()

              // Check rate limit
              if (!rateLimiter.isAllowed(request.userId)) {
                complete(StatusCodes.TooManyRequests, QueryResponse(
                  status = "error", data = None, schema = None, rowCount = None,
                  error = Some("Rate limit exceeded. Please try again later."),
                  queryId = java.util.UUID.randomUUID().toString
                ))
              } else {
                // Get user permissions
                permissionsStore.getPermissions(request.userId) match {
                  case None =>
                    complete(StatusCodes.Forbidden, QueryResponse(
                      status = "error", data = None, schema = None, rowCount = None,
                      error = Some("User not authorized to execute queries"),
                      queryId = java.util.UUID.randomUUID().toString
                    ))
                  case Some(perms) =>
                    // Create user-specific validator
                    val validator = new SqlQueryValidator(perms.allowedDatabases, perms.allowedTables)
                    val executor = new SecureQueryExecutor(spark, validator)

                    val adjustedRequest = request.copy(
                      maxRows = Some(math.min(
                        request.maxRows.getOrElse(perms.maxRowsPerQuery),
                        perms.maxRowsPerQuery
                      ))
                    )

                    val resultFuture = executor.executeQuery(adjustedRequest)

                    onComplete(resultFuture) {
                      case Success(response) =>
                        val elapsed = System.currentTimeMillis() - startTime
                        auditLogger.log(
                          request.userId, response.queryId, request.sql,
                          response.status, response.error, elapsed
                        )

                        val statusCode = response.status match {
                          case "success" => StatusCodes.OK
                          case _ => StatusCodes.BadRequest
                        }
                        complete(statusCode, response)

                      case Failure(e) =>
                        val elapsed = System.currentTimeMillis() - startTime
                        val queryId = java.util.UUID.randomUUID().toString
                        auditLogger.log(
                          request.userId, queryId, request.sql,
                          "error", Some(e.getMessage), elapsed
                        )
                        complete(StatusCodes.InternalServerError, QueryResponse(
                          status = "error", data = None, schema = None, rowCount = None,
                          error = Some("Internal server error"),
                          queryId = queryId
                        ))
                    }
                }
              }
            }
          }
        } ~
        path("health") {
          get {
            complete(StatusCodes.OK, """{"status": "healthy"}""")
          }
        }
      }

    val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

    bindingFuture.onComplete {
      case Success(binding) =>
        println(s"Secure Analytics Platform running at ${binding.localAddress}")
      case Failure(e) =>
        println(s"Failed to start server: ${e.getMessage}")
        system.terminate()
    }

    // Shutdown hook
    sys.addShutdownHook {
      auditLogger.flush()
      spark.stop()
      system.terminate()
    }
  }

  private def registerSampleData(spark: SparkSession): Unit = {
    import spark.implicits._

    // Create sample databases and tables
    spark.sql("CREATE DATABASE IF NOT EXISTS analytics")
    spark.sql("CREATE DATABASE IF NOT EXISTS reporting")

    // Sample page_views table
    val pageViews = Seq(
      (1, "user_001", "/home", "2024-01-15 10:30:00", "Chrome", "US"),
      (2, "user_002", "/products", "2024-01-15 10:31:00", "Firefox", "UK"),
      (3, "user_001", "/checkout", "2024-01-15 10:35:00", "Chrome", "US"),
      (4, "user_003", "/home", "2024-01-15 11:00:00", "Safari", "CA"),
      (5, "user_002", "/about", "2024-01-15 11:15:00", "Firefox", "UK")
    ).toDF("id", "user_id", "page", "timestamp", "browser", "country")

    pageViews.write.mode("overwrite").saveAsTable("analytics.page_views")

    // Sample user_sessions table
    val sessions = Seq(
      ("session_001", "user_001", "2024-01-15 10:00:00", "2024-01-15 10:45:00", 3, 270),
      ("session_002", "user_002", "2024-01-15 10:30:00", "2024-01-15 11:20:00", 2, 300),
      ("session_003", "user_003", "2024-01-15 11:00:00", "2024-01-15 11:30:00", 1, 180)
    ).toDF("session_id", "user_id", "start_time", "end_time", "page_count", "duration_seconds")

    sessions.write.mode("overwrite").saveAsTable("analytics.user_sessions")

    // Sample daily_metrics table
    val dailyMetrics = Seq(
      ("2024-01-15", 1500, 300, 45, 12500.50),
      ("2024-01-14", 1400, 280, 40, 11200.75),
      ("2024-01-13", 1600, 320, 50, 13800.25)
    ).toDF("date", "total_visits", "unique_visitors", "conversions", "revenue")

    dailyMetrics.write.mode("overwrite").saveAsTable("reporting.daily_metrics")

    println("Sample data registered successfully.")
  }
}